#pragma alloc_text(PAGE, DriverReadHandler)
NTSTATUS DriverReadHandler(_In_ PDEVICE_OBJECT DeviceObject, _In_ PIRP Irp) {
    UNREFERENCED_PARAMETER(DeviceObject);
    Irp->IoStatus.Status = STATUS_SUCCESS;
    IoCompleteRequest(Irp, IO_NO_INCREMENT);
    return STATUS_SUCCESS;
}
NTSTATUS DispatchHandler(_In_ PDEVICE_OBJECT DeviceObject, _In_ PIRP Irp) {
    KIRQL oldIrql;
    UNREFERENCED_PARAMETER(DeviceObject);
    KeAcquireSpinLock(&g_Lock, &oldIrql);
    PAGED_CODE();
    KeReleaseSpinLock(&g_Lock, oldIrql);
    IoCompleteRequest(Irp, IO_NO_INCREMENT);
    return STATUS_SUCCESS;
}
